diff --git a/webservice/src/test/java/com/finbit/fiuadapter/webservice/service/externalentity/FiuHelperBoundaryTest.java b/webservice/src/test/java/com/finbit/fiuadapter/webservice/service/externalentity/FiuHelperBoundaryTest.java
new file mode 100644
index 0000000..49bd58a
--- /dev/null
+++ b/webservice/src/test/java/com/finbit/fiuadapter/webservice/service/externalentity/FiuHelperBoundaryTest.java
@@ -0,0 +1,233 @@
+package com.finbit.fiuadapter.webservice.service.externalentity;
+
+import com.finbit.fiuadapter.webservice.constants.GeneralConstants;
+import com.finbit.fiuadapter.webservice.entity.EntityDetails;
+import com.finbit.fiuadapter.webservice.exceptions.DataException;
+import com.finbit.fiuadapter.webservice.exceptions.InvalidRequestException;
+import com.finbit.fiuadapter.webservice.representation.pojo.ApplicationConfigurationBean;
+import com.finbit.fiuadapter.webservice.representation.request.ConsentNotificationRequest;
+import com.finbit.fiuadapter.webservice.representation.request.ConsentStatusNotification;
+import com.finbit.fiuadapter.webservice.representation.request.Notifier;
+import com.finbit.fiuadapter.webservice.representation.response.OneMoneyConfigeResponse;
+import com.finbit.fiuadapter.webservice.service.consentnotification.ConsentNotificationValidationImpl;
+import com.finbit.fiuadapter.webservice.service.signature.verification.HeaderTokenSignatureVerificationServiceImpl;
+import com.finbit.fiuadapter.webservice.utils.BeansUtils;
+import com.finbit.fiuadapter.webservice.utils.GetDetachedBody;
+import org.junit.jupiter.api.Test;
+
+import static org.junit.jupiter.api.Assertions.assertEquals;
+import static org.junit.jupiter.api.Assertions.assertNull;
+import static org.junit.jupiter.api.Assertions.assertThrows;
+import static org.junit.jupiter.api.Assertions.assertTrue;
+
+/**
+ * Boundary / edge-case correctness for the deterministic parsing, object-copy,
+ * request-validation and config-mapping helpers the FIU adapter relies on. Every
+ * assertion drives a pure, side-effect-free entry point (a static util, a
+ * bare-constructed stateless service, or a bare-constructed mapper) with plain
+ * POJO / primitive inputs; there is no Spring context, no database and no
+ * network, and no collaborator is mocked.
+ *
+ * The wider application only ever exercises these helpers on the well-formed
+ * values it produces itself (full three-part JWS tokens, single-field
+ * validation misses, non-blank config values), so the boundary slips asserted
+ * here never surface in ordinary use.
+ */
+public class FiuHelperBoundaryTest {
+
+    // ---- helpers ------------------------------------------------------------
+
+    /** A fully-populated consent notification (no missing/blank fields). */
+    private static ConsentNotificationRequest fullConsentNotification() {
+        ConsentNotificationRequest req = new ConsentNotificationRequest();
+        req.setVer("1.0");
+        req.setTimestamp("2022-01-15T13:30:45.000Z");
+        req.setTxnid("txn-0001");
+        Notifier notifier = new Notifier();
+        notifier.setId("aa-0001");
+        notifier.setType("AA");
+        req.setNotifier(notifier);
+        ConsentStatusNotification csn = new ConsentStatusNotification();
+        csn.setConsentId("consent-id-0001");
+        csn.setConsentHandle("consent-handle-0001");
+        csn.setConsentStatus("ACTIVE"); // non-null, non-REJECTED so consentId is checked
+        req.setConsentStatusNotification(csn);
+        return req;
+    }
+
+    private static EntityDetails fiuWithBranding() {
+        EntityDetails ed = new EntityDetails();
+        ed.setCompanyName("Acme Bank");
+        ed.setCompanyColor("#00FF00");
+        ed.setCompanyLogo("acme-logo.png");
+        return ed;
+    }
+
+    private static ApplicationConfigurationBean appConfig(String identifierValue) {
+        ApplicationConfigurationBean cfg = new ApplicationConfigurationBean();
+        cfg.setIdentifierValue(identifierValue);
+        cfg.setAppIdentifier("app-identifier-x");
+        cfg.setBaseURL("https://base.example");
+        return cfg;
+    }
+
+    // ---- fail_to_pass : one per planted boundary defect ---------------------
+
+    /** D1: the detached-signature helper returns the signature (last) segment. */
+    @Test
+    public void getDetached_returnsSignatureSegment() {
+        // A JWS compact serialization is header.payload.signature; the detached
+        // signature is the third (last) segment.
+        assertEquals("ccc", GetDetachedBody.getDetached("aaa.bbb.ccc"));
+    }
+
+    /** D2: copying with ignore-nulls skips only the null source properties. */
+    @Test
+    public void copyProperties_ignoreNulls_keepsFilledDropsBlanks() {
+        Notifier source = new Notifier();
+        source.setId("newId");
+        source.setType(null);
+        Notifier dest = new Notifier();
+        dest.setId("oldId");
+        dest.setType("keepType");
+        BeansUtils.copyProperties(source, dest, true);
+        // the non-null source property overwrites the destination ...
+        assertEquals("newId", dest.getId());
+        // ... and the null source property is skipped, so the destination keeps its value
+        assertEquals("keepType", dest.getType());
+    }
+
+    /** D3: an api key with fewer than the required segments is rejected. */
+    @Test
+    public void verifyAAApiKey_rejectsTokenWithTooFewSegments() {
+        HeaderTokenSignatureVerificationServiceImpl svc = new HeaderTokenSignatureVerificationServiceImpl();
+        // "aa.YWFh" has only two dot-separated segments (a signed token needs
+        // header, payload and signature); it must be rejected as malformed.
+        assertThrows(DataException.class, () -> svc.verifyAAApiKey("aa.YWFh"));
+    }
+
+    /** D4: exactly one missing field yields the single-field error message. */
+    @Test
+    public void validateRequestFields_singleMissingFieldUsesSingularMessage() {
+        ConsentNotificationRequest req = fullConsentNotification();
+        req.getConsentStatusNotification().setConsentId(""); // exactly one blank field
+        InvalidRequestException ex = assertThrows(InvalidRequestException.class,
+                () -> new ConsentNotificationValidationImpl().validateRequestFields(req));
+        assertTrue(ex.getErrorMessage().endsWith(GeneralConstants.ERROR_MESSAGE),
+                "expected the single-field message, got: " + ex.getErrorMessage());
+    }
+
+    /** D5: the config response maps the company name from the company name. */
+    @Test
+    public void oneMoneyConfig_mapsCompanyNameFromCompanyName() {
+        OneMoneyConfigeResponse resp =
+                new AAEntityServiceImpl().mapOneMoneyConfigResponse(fiuWithBranding(), appConfig("mobile"));
+        assertEquals("Acme Bank", resp.getCompanyName());
+    }
+
+    // ---- pass_to_pass : behaviour unchanged by the planted defects ----------
+
+    @Test
+    public void getDetached_equalTailSegmentsAreStable() {
+        // when the last two segments coincide the returned value is invariant
+        assertEquals("sig", GetDetachedBody.getDetached("header.sig.sig"));
+    }
+
+    @Test
+    public void copyProperties_withoutIgnore_copiesEveryProperty() {
+        Notifier source = new Notifier();
+        source.setId("srcId");
+        source.setType(null);
+        Notifier dest = new Notifier();
+        dest.setId("dstId");
+        dest.setType("dstType");
+        BeansUtils.copyProperties(source, dest, false);
+        assertEquals("srcId", dest.getId());
+        assertNull(dest.getType());
+    }
+
+    @Test
+    public void copyProperties_withoutIgnore_overwritesWithNonNull() {
+        Notifier source = new Notifier();
+        source.setId("copiedId");
+        source.setType("copiedType");
+        Notifier dest = new Notifier();
+        dest.setId("x");
+        dest.setType("y");
+        BeansUtils.copyProperties(source, dest, false);
+        assertEquals("copiedId", dest.getId());
+        assertEquals("copiedType", dest.getType());
+    }
+
+    @Test
+    public void verifyAAApiKey_emptyIsRejected() {
+        HeaderTokenSignatureVerificationServiceImpl svc = new HeaderTokenSignatureVerificationServiceImpl();
+        assertThrows(DataException.class, () -> svc.verifyAAApiKey(""));
+    }
+
+    @Test
+    public void verifyAAApiKey_nullIsRejected() {
+        HeaderTokenSignatureVerificationServiceImpl svc = new HeaderTokenSignatureVerificationServiceImpl();
+        assertThrows(DataException.class, () -> svc.verifyAAApiKey(null));
+    }
+
+    @Test
+    public void verifyAAApiKey_singleSegmentIsRejected() {
+        HeaderTokenSignatureVerificationServiceImpl svc = new HeaderTokenSignatureVerificationServiceImpl();
+        assertThrows(DataException.class, () -> svc.verifyAAApiKey("onlyonesegment"));
+    }
+
+    @Test
+    public void validateRequestFields_multipleMissingUsesPluralMessage() {
+        ConsentNotificationRequest req = fullConsentNotification();
+        req.getConsentStatusNotification().setConsentId("");
+        req.getConsentStatusNotification().setConsentHandle("");
+        req.setTxnid(""); // three blank fields
+        InvalidRequestException ex = assertThrows(InvalidRequestException.class,
+                () -> new ConsentNotificationValidationImpl().validateRequestFields(req));
+        assertTrue(ex.getErrorMessage().endsWith(GeneralConstants.SCHEMATIC_ERROR_MSG),
+                "expected the multi-field message, got: " + ex.getErrorMessage());
+    }
+
+    @Test
+    public void validateRequestFields_fourMissingUsesPluralMessage() {
+        ConsentNotificationRequest req = fullConsentNotification();
+        req.getConsentStatusNotification().setConsentId("");
+        req.getConsentStatusNotification().setConsentHandle("");
+        req.setTxnid("");
+        req.setTimestamp(""); // four blank fields
+        InvalidRequestException ex = assertThrows(InvalidRequestException.class,
+                () -> new ConsentNotificationValidationImpl().validateRequestFields(req));
+        assertTrue(ex.getErrorMessage().endsWith(GeneralConstants.SCHEMATIC_ERROR_MSG),
+                "expected the multi-field message, got: " + ex.getErrorMessage());
+    }
+
+    @Test
+    public void oneMoneyConfig_mapsCompanyColor() {
+        OneMoneyConfigeResponse resp =
+                new AAEntityServiceImpl().mapOneMoneyConfigResponse(fiuWithBranding(), appConfig("mobile"));
+        assertEquals("#00FF00", resp.getCompanyColor());
+    }
+
+    @Test
+    public void oneMoneyConfig_mapsCompanyLogo() {
+        OneMoneyConfigeResponse resp =
+                new AAEntityServiceImpl().mapOneMoneyConfigResponse(fiuWithBranding(), appConfig("mobile"));
+        assertEquals("acme-logo.png", resp.getCompanyLogo());
+    }
+
+    @Test
+    public void oneMoneyConfig_passesThroughAppIdentifier() {
+        OneMoneyConfigeResponse resp =
+                new AAEntityServiceImpl().mapOneMoneyConfigResponse(fiuWithBranding(), appConfig("mobile"));
+        assertEquals("app-identifier-x", resp.getAppIdentifier());
+    }
+
+    @Test
+    public void oneMoneyConfig_blanksLiteralNullIdentifierValue() {
+        // the literal string "null" sentinel is normalised to an empty string
+        OneMoneyConfigeResponse resp =
+                new AAEntityServiceImpl().mapOneMoneyConfigResponse(fiuWithBranding(), appConfig("null"));
+        assertEquals("", resp.getIdentifierValue());
+    }
+}
